css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { min-height: 100vh; display: flex; align-items: center; justify-content: center; background: radial-gradient(ellipse at top, #0a2e15 0%, #070b18 60%); padding: 24px; }
.card { width: 100%; max-width: 420px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 24px; padding: 40px 36px; backdrop-filter: blur(20px); box-shadow: 0 30px 60px rgba(0,0,0,0.4); text-align: center; }
.check-circle { width: 76px; height: 76px; border-radius: 50%; background: linear-gradient(135deg, #22c55e, #16a34a); display: flex; align-items: center; justify-content: center; margin: 0 auto 22px; box-shadow: 0 0 0 8px rgba(34,197,94,0.1), 0 10px 30px rgba(34,197,94,0.35); animation: pop 0.5s ease; }
#checkPath { stroke-dasharray: 30; stroke-dashoffset: 30; animation: draw 0.5s ease 0.3s forwards; }
@keyframes pop { from { transform: scale(0); opacity: 0; } to { transform: scale(1); opacity: 1; } }
@keyframes draw { to { stroke-dashoffset: 0; } }
h1 { color: white; font-size: 24px; font-weight: 700; margin-bottom: 10px; }
.sub { color: rgba(255,255,255,0.55); font-size: 14px; line-height: 1.6; margin-bottom: 26px; }
.sub strong { color: #4ade80; }
.details { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 14px; padding: 16px 18px; margin-bottom: 24px; text-align: left; }
.details .row { display: flex; justify-content: space-between; padding: 7px 0; font-size: 13px; }
.details .row span:first-child { color: rgba(255,255,255,0.45); }
.details .row .value { color: white; font-weight: 600; }
.btn-primary { width: 100%; padding: 15px; border: none; border-radius: 12px; background: linear-gradient(135deg, #22c55e, #16a34a); color: white; font-size: 15px; font-weight: 700; cursor: pointer; box-shadow: 0 12px 30px rgba(34,197,94,0.3); margin-bottom: 10px; }
.btn-secondary { width: 100%; padding: 14px; border: 1px solid rgba(255,255,255,0.12); border-radius: 12px; background: transparent; color: white; font-size: 14px; font-weight: 600; cursor: pointer; }

